#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        long long X;
        scanf("%d %lld", &N, &X);
        long long *a = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) {
            scanf("%lld", &a[i]);
        }
        long long sum = 0;
        for (int i = 0; i < (N + 1) / 2; ++i) {
            long long left = a[i];
            long long right = a[N - 1 - i];
            sum += (left > right) ? left : right;
        }
        if (sum >= X) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
        free(a);
    }
    return 0;
}

